// import logo from './logo.svg';
import python from './python.svg';
import './App.css';
import Api_fetching from './APIfetching';


function App() {
  return (
    <div className="App">
      <header className="App-header">
        <img src={python} className="App-logo" alt="logo" />

        <Api_fetching></Api_fetching>
        <p>
          Data Fetching with React & Flask 
        </p>
        <a
          className="App-link"
          href="https://www.geeksforgeeks.org/how-to-connect-reactjs-with-flask-api/"
          target="_blank"
          rel="noopener noreferrer"
        >
          Learn more
        </a>
      </header>
    </div>
  );
}

export default App;



